fn phase_to_string(phase: &Phase) -> &'static str {
    match phase {
        Phase::Absent => "Absent",
        Phase::Running => "Running",
        Phase::Completed => "Completed",
        Phase::Exhausted => "Exhausted",
        Phase::Failed => "Failed",
        Phase::Canceled => "Canceled",
    }
}

fn phase_from_string(phase: &str) -> Result<Phase, KernelError> {
    match phase {
        "Absent" => Ok(Phase::Absent),
        "Running" => Ok(Phase::Running),
        "Completed" => Ok(Phase::Completed),
        "Exhausted" => Ok(Phase::Exhausted),
        "Failed" => Ok(Phase::Failed),
        "Canceled" => Ok(Phase::Canceled),
        other => Err(KernelError::CodegenInvariant {
            detail: format!("unknown phase `{other}`"),
        }),
    }
}

fn take_field(
    fields: &mut std::collections::BTreeMap<String, KernelValue>,
    container: &str,
    field: &str,
) -> Result<KernelValue, KernelError> {
    fields
        .remove(field)
        .ok_or_else(|| KernelError::CodegenInvariant {
            detail: format!("{container} missing field `{field}`"),
        })
}

fn outcome_from_kernel(outcome: LegacyTransitionOutcome) -> Result<Outcome, KernelError> {
    let transition_id = transition_id_from_str(&outcome.transition).ok_or_else(|| {
        KernelError::CodegenInvariant {
            detail: format!("unknown transition id `{}`", outcome.transition),
        }
    })?;
    Ok(Outcome {
        transition_id,
        next_state: state_from_kernel(outcome.next_state)?,
        effects: outcome
            .effects
            .into_iter()
            .map(effect_from_kernel)
            .collect::<Result<Vec<_>, _>>()?,
    })
}

fn map_legacy_error(
    error: LegacyTransitionRefusal,
    phase: Phase,
    trigger: TriggerDiscriminant,
) -> TransitionError {
    match error {
        LegacyTransitionRefusal::NoMatchingTransition { .. } => {
            let rejections = guard_rejections_for_trigger(&phase, &trigger);
            if rejections.is_empty() {
                TransitionError::Refusal(TransitionRefusal::NoMatchingTransition { phase, trigger })
            } else {
                TransitionError::Refusal(TransitionRefusal::GuardRejected { rejections })
            }
        }
        LegacyTransitionRefusal::AmbiguousTransition { transitions, .. } => {
            let mut typed = Vec::new();
            for transition in transitions {
                let Some(transition_id) = transition_id_from_str(&transition) else {
                    return TransitionError::Kernel(KernelError::CodegenInvariant {
                        detail: format!("unknown transition `{transition}` in ambiguity report"),
                    });
                };
                typed.push(transition_id);
            }
            TransitionError::Refusal(TransitionRefusal::AmbiguousTransition { transitions: typed })
        }
        LegacyTransitionRefusal::EvaluationError {
            transition, reason, ..
        } => {
            if let Some(transition_id) = transition_id_from_str(&transition) {
                TransitionError::Kernel(KernelError::ContextViolation {
                    transition_id,
                    detail: reason,
                })
            } else {
                TransitionError::Kernel(KernelError::CodegenInvariant {
                    detail: format!(
                        "unknown transition `{transition}` in evaluation error: {reason}"
                    ),
                })
            }
        }
        other => TransitionError::Kernel(KernelError::CodegenInvariant {
            detail: other.to_string(),
        }),
    }
}

#[allow(dead_code)]
fn map_helper_error(helper_id: HelperId, error: LegacyTransitionRefusal) -> KernelError {
    match error {
        LegacyTransitionRefusal::EvaluationError { reason, .. } => KernelError::HelperEvaluation {
            helper_id,
            detail: reason,
        },
        other => KernelError::CodegenInvariant {
            detail: other.to_string(),
        },
    }
}

fn guard_rejections_for_trigger(
    phase: &Phase,
    trigger: &TriggerDiscriminant,
) -> Vec<GuardRejection> {
    match (phase, trigger) {
        (Phase::Running, TriggerDiscriminant::Input(LoopIterationInputKind::BodyFrameCanceled)) => {
            vec![
                GuardRejection {
                    transition_id: TransitionId::BodyFrameCanceled,
                    guard_id: GuardId::BodyFrameCanceledGuard1,
                },
                GuardRejection {
                    transition_id: TransitionId::BodyFrameCanceled,
                    guard_id: GuardId::BodyFrameCanceledGuard2,
                },
                GuardRejection {
                    transition_id: TransitionId::BodyFrameCanceled,
                    guard_id: GuardId::BodyFrameCanceledGuard3,
                },
            ]
        }
        (
            Phase::Running,
            TriggerDiscriminant::Input(LoopIterationInputKind::BodyFrameCompleted),
        ) => vec![
            GuardRejection {
                transition_id: TransitionId::BodyFrameCompleted,
                guard_id: GuardId::BodyFrameCompletedGuard1,
            },
            GuardRejection {
                transition_id: TransitionId::BodyFrameCompleted,
                guard_id: GuardId::BodyFrameCompletedGuard2,
            },
            GuardRejection {
                transition_id: TransitionId::BodyFrameCompleted,
                guard_id: GuardId::BodyFrameCompletedGuard3,
            },
        ],
        (Phase::Running, TriggerDiscriminant::Input(LoopIterationInputKind::BodyFrameFailed)) => {
            vec![
                GuardRejection {
                    transition_id: TransitionId::BodyFrameFailed,
                    guard_id: GuardId::BodyFrameFailedGuard1,
                },
                GuardRejection {
                    transition_id: TransitionId::BodyFrameFailed,
                    guard_id: GuardId::BodyFrameFailedGuard2,
                },
                GuardRejection {
                    transition_id: TransitionId::BodyFrameFailed,
                    guard_id: GuardId::BodyFrameFailedGuard3,
                },
            ]
        }
        (Phase::Running, TriggerDiscriminant::Input(LoopIterationInputKind::BodyFrameStarted)) => {
            vec![
                GuardRejection {
                    transition_id: TransitionId::BodyFrameStarted,
                    guard_id: GuardId::BodyFrameStartedGuard1,
                },
                GuardRejection {
                    transition_id: TransitionId::BodyFrameStarted,
                    guard_id: GuardId::BodyFrameStartedGuard2,
                },
                GuardRejection {
                    transition_id: TransitionId::BodyFrameStarted,
                    guard_id: GuardId::BodyFrameStartedGuard3,
                },
            ]
        }
        (Phase::Running, TriggerDiscriminant::Input(LoopIterationInputKind::CancelLoop)) => {
            vec![GuardRejection {
                transition_id: TransitionId::CancelLoop,
                guard_id: GuardId::CancelLoopGuard1,
            }]
        }
        (
            Phase::Running,
            TriggerDiscriminant::Input(LoopIterationInputKind::UntilConditionFailed),
        ) => vec![
            GuardRejection {
                transition_id: TransitionId::UntilConditionFailed,
                guard_id: GuardId::UntilConditionFailedGuard1,
            },
            GuardRejection {
                transition_id: TransitionId::UntilConditionFailed,
                guard_id: GuardId::UntilConditionFailedGuard2,
            },
            GuardRejection {
                transition_id: TransitionId::UntilConditionFailed,
                guard_id: GuardId::UntilConditionFailedGuard3,
            },
            GuardRejection {
                transition_id: TransitionId::UntilConditionFailed,
                guard_id: GuardId::UntilConditionFailedGuard4,
            },
            GuardRejection {
                transition_id: TransitionId::ExhaustedIterations,
                guard_id: GuardId::ExhaustedIterationsGuard1,
            },
            GuardRejection {
                transition_id: TransitionId::ExhaustedIterations,
                guard_id: GuardId::ExhaustedIterationsGuard2,
            },
            GuardRejection {
                transition_id: TransitionId::ExhaustedIterations,
                guard_id: GuardId::ExhaustedIterationsGuard3,
            },
            GuardRejection {
                transition_id: TransitionId::ExhaustedIterations,
                guard_id: GuardId::ExhaustedIterationsGuard4,
            },
        ],
        (Phase::Running, TriggerDiscriminant::Input(LoopIterationInputKind::UntilConditionMet)) => {
            vec![
                GuardRejection {
                    transition_id: TransitionId::UntilConditionMet,
                    guard_id: GuardId::UntilConditionMetGuard1,
                },
                GuardRejection {
                    transition_id: TransitionId::UntilConditionMet,
                    guard_id: GuardId::UntilConditionMetGuard2,
                },
                GuardRejection {
                    transition_id: TransitionId::UntilConditionMet,
                    guard_id: GuardId::UntilConditionMetGuard3,
                },
            ]
        }
        _ => Vec::new(),
    }
}

fn kernel_option_some(value: KernelValue) -> KernelValue {
    KernelValue::Map(std::collections::BTreeMap::from([(
        KernelValue::String("value".to_string()),
        value,
    )]))
}

fn kernel_type_error(context: &str, expected: &str, value: &KernelValue) -> KernelError {
    KernelError::CodegenInvariant {
        detail: format!("{context} expected {expected}, found {value:?}"),
    }
}

