#[allow(dead_code)]
fn value_to_kernel_enum_loop_iteration_stage(
    value: &compat_types::LoopIterationStage,
) -> KernelValue {
    let variant = match value {
        compat_types::LoopIterationStage::AwaitingBodyFrame => "AwaitingBodyFrame",
        compat_types::LoopIterationStage::BodyFrameActive => "BodyFrameActive",
        compat_types::LoopIterationStage::AwaitingUntil => "AwaitingUntil",
    };
    KernelValue::NamedVariant {
        enum_name: "LoopIterationStage".to_string(),
        variant: variant.to_string(),
    }
}

#[allow(dead_code)]
fn value_from_kernel_enum_loop_iteration_stage(
    value: KernelValue,
    context: &str,
) -> Result<compat_types::LoopIterationStage, KernelError> {
    match value {
        KernelValue::NamedVariant { enum_name, variant } if enum_name == "LoopIterationStage" => {
            match variant.as_str() {
                "AwaitingBodyFrame" => Ok(compat_types::LoopIterationStage::AwaitingBodyFrame),
                "BodyFrameActive" => Ok(compat_types::LoopIterationStage::BodyFrameActive),
                "AwaitingUntil" => Ok(compat_types::LoopIterationStage::AwaitingUntil),
                other => Err(KernelError::CodegenInvariant {
                    detail: format!(
                        "{context} expected LoopIterationStage variant, found `{other}`"
                    ),
                }),
            }
        }
        other => Err(kernel_type_error(context, "LoopIterationStage", &other)),
    }
}

#[allow(dead_code)]
fn value_to_kernel_option_named_frame_id(value: &Option<compat_types::FrameId>) -> KernelValue {
    match value {
        Some(inner) => kernel_option_some(value_to_kernel_named_frame_id(inner)),
        None => KernelValue::None,
    }
}

#[allow(dead_code)]
fn value_from_kernel_option_named_frame_id(
    value: KernelValue,
    context: &str,
) -> Result<Option<compat_types::FrameId>, KernelError> {
    match value {
        KernelValue::None => Ok(None),
        KernelValue::Map(mut entries) => {
            if let Some(inner) = entries.remove(&KernelValue::String("value".to_string())) {
                Ok(Some(value_from_kernel_named_frame_id(inner, context)?))
            } else {
                Err(KernelError::CodegenInvariant {
                    detail: format!("{context} expected option value payload"),
                })
            }
        }
        other => Ok(Some(value_from_kernel_named_frame_id(other, context)?)),
    }
}
